SELECT id, resume_name,user_id, name, phone, email, age, gender,skills,
self_description, job_intention, city, salary_min, salary_max,
job_type, industry, available_from, graduation_school,
total_work_years, max_education,
created_at, updated_at,is_default,character_avatar
FROM resumes


        AND user_id = #{userId}


        AND city = #{city}


        AND job_intention LIKE CONCAT('%', #{jobIntention}, '%')


        AND total_work_years >= #{totalWorkYears}


        AND max_education >= #{maxEducation}


        and salary_min >= #{salaryMin}
        and salary_max <= #{salaryMax}



        AND (name LIKE CONCAT('%', #{keyword}, '%')
        OR job_intention LIKE CONCAT('%', #{keyword}, '%')
        OR skills LIKE CONCAT('%', #{keyword}, '%'))

and is_default = 1

ORDER BY updated_at DESC

